@Test
public void testIsSupportLowerBoundInclusiveWithInfiniteBound() {
    if (Double.isInfinite(distribution.getSupportLowerBound())) {
        Assert.assertFalse("Lower bound should not be inclusive when infinite",
                distribution.isSupportLowerBoundInclusive());
    }
}

@Test
public void testIsSupportUpperBoundInclusiveWithInfiniteBound() {
    if (Double.isInfinite(distribution.getSupportUpperBound())) {
        Assert.assertFalse("Upper bound should not be inclusive when infinite",
                distribution.isSupportUpperBoundInclusive());
    }
}
